@namespace Lumeo

@if (ShowScrim && !IsCollapsed)
{
    <div class="absolute inset-0 z-30 bg-black/50 transition-opacity" aria-hidden="true" @onclick="DismissOverlay"></div>
}
<aside class="@CssClass"
       aria-expanded="@(EffectivelyExpanded ? "true" : "false")"
       @onmouseenter="OnHoverEnter" @onmouseleave="OnHoverLeave"
       @onfocusin="OnHoverEnter" @onfocusout="OnHoverLeave"
       @attributes="AdditionalAttributes">
    @ChildContent
</aside>

@code {
    [CascadingParameter] public SidebarProvider.SidebarState? State { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Which edge the sidebar anchors to. Only <see cref="Lumeo.Side.Left"/>
    /// and <see cref="Lumeo.Side.Right"/> are supported; <c>Top</c>/<c>Bottom</c>
    /// fall through to the <see cref="Lumeo.Side.Left"/> default.</summary>
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Left;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsCollapsed => State?.IsCollapsed ?? false;
    private SidebarProvider.SidebarVariant Variant => State?.Variant ?? SidebarProvider.SidebarVariant.Push;
    private bool IsMiniRail => Variant == SidebarProvider.SidebarVariant.MiniRail;

    // On a mobile viewport (when the provider opted in), every variant renders
    // as an off-canvas sheet. This overrides the variant geometry below. (#241)
    private bool IsMobileSheet => State?.IsMobileSheet ?? false;

    // The scrim is shown for the Overlay variant and for the mobile sheet.
    private bool ShowScrim => IsMobileSheet || Variant == SidebarProvider.SidebarVariant.Overlay;

    // The "effective" state from the provider. Drives both the rail width AND the
    // SidebarMenuButton label visibility via the cascade — without it MiniRail's
    // hover-expansion only widened the rail while labels stayed hidden.
    private bool EffectiveCollapsed => State?.EffectiveCollapsed ?? IsCollapsed;
    private bool EffectivelyExpanded => !EffectiveCollapsed;

    private string CssClass
    {
        get
        {
            var baseCss = "flex h-full flex-col border-e bg-sidebar text-sidebar-foreground overflow-y-auto overflow-x-hidden transition-all duration-300";

            // Mobile sheet: a slide-in panel anchored to the edge, above content,
            // collapsed = translated fully off-canvas. Same treatment as Overlay
            // but forced on for ANY variant while on mobile.
            var variantCss = IsMobileSheet
                ? $"absolute z-40 top-0 {(Side == Lumeo.Side.Right ? "end-0" : "start-0")} w-64 shadow-xl {(IsCollapsed ? (Side == Lumeo.Side.Right ? "translate-x-full" : "-translate-x-full") : "translate-x-0")}"
                : Variant switch
                {
                    SidebarProvider.SidebarVariant.Overlay =>
                        $"absolute z-40 top-0 {(Side == Lumeo.Side.Right ? "end-0" : "start-0")} w-64 shadow-xl {(IsCollapsed ? (Side == Lumeo.Side.Right ? "translate-x-full" : "-translate-x-full") : "translate-x-0")}",
                    SidebarProvider.SidebarVariant.Icon => $"shrink-0 {(IsCollapsed ? "w-16" : "w-64")}",
                    // MiniRail widens to w-64 whenever it's effectively expanded — pinned open
                    // OR hover/focus active. The provider owns the hover bit so the same flag
                    // flows to descendant labels via the cascade.
                    SidebarProvider.SidebarVariant.MiniRail => $"shrink-0 {(EffectiveCollapsed ? "w-16" : "w-64")}",
                    _ => $"shrink-0 {(IsCollapsed ? "w-0 border-e-0" : "w-64")}"
                };

            var sideCss = Side == Lumeo.Side.Right ? "order-last border-s border-e-0" : "";

            return Cx.Merge(baseCss, variantCss, sideCss, Class);
        }
    }

    private async Task DismissOverlay()
    {
        if (State is not null)
            await State.Toggle.InvokeAsync();
    }

    // Hover / focus handlers route to the provider so the effective state propagates
    // through the cascade. Only MiniRail acts on the flag in its CSS / label logic;
    // other variants ignore it (cheap no-op).
    private async Task OnHoverEnter()
    {
        if (!IsMiniRail || !IsCollapsed || State is null) return;
        await State.SetHoverExpanded.InvokeAsync(true);
    }

    private async Task OnHoverLeave()
    {
        if (State is null) return;
        await State.SetHoverExpanded.InvokeAsync(false);
    }
}

