@namespace Lumeo
@inject IComponentInteropService Interop
@inject Lumeo.Services.IResponsiveService Responsive
@inject Lumeo.Services.IKeyboardShortcutService Shortcuts
@implements IAsyncDisposable

@{
    var context = new SidebarState(
        IsCollapsed,
        EventCallback.Factory.Create(this, Toggle),
        Variant)
    {
        EffectiveCollapsed = EffectiveCollapsed,
        SetHoverExpanded = EventCallback.Factory.Create<bool>(this, SetHoverExpanded),
        IsMobileSheet = IsMobileSheet,
    };
}

<CascadingValue Value="context" IsFixed="false">
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool IsCollapsed { get; set; }
    [Parameter] public EventCallback<bool> IsCollapsedChanged { get; set; }
    [Parameter] public SidebarVariant Variant { get; set; } = SidebarVariant.Push;

    /// <summary>
    /// When true, the sidebar renders as an off-canvas sheet (slide-in over a
    /// dismissible scrim) on mobile viewports (&lt; <c>md</c>), regardless of
    /// <see cref="Variant"/>. On larger viewports it keeps its configured
    /// variant. Collapsed acts as the sheet's closed state; toggling opens it.
    /// Opt-in (default false) so existing layouts are unchanged. (#241)
    /// </summary>
    [Parameter] public bool MobileSheet { get; set; }

    /// <summary>
    /// Optional keyboard shortcut that toggles the sidebar, in the
    /// <see cref="Lumeo.Services.IKeyboardShortcutService"/> combo format
    /// (e.g. <c>"ctrl+b"</c>, <c>"meta+b"</c>). Registered on first render and
    /// released on dispose. Null disables the shortcut. (#241)
    /// </summary>
    [Parameter] public string? ToggleShortcut { get; set; }

    /// <summary>
    /// When true, the collapsed / expanded state survives page reloads — the provider
    /// reads <see cref="IsCollapsed"/> from <c>localStorage[PersistenceKey]</c> on first
    /// render and writes back on every change. Falls back to the parameter value when
    /// JS is unavailable (SSR, prerender, JSDisconnectedException). Opt-in to keep
    /// existing consumers' behaviour untouched.
    /// </summary>
    [Parameter] public bool PersistCollapsed { get; set; }

    /// <summary>
    /// LocalStorage key used when <see cref="PersistCollapsed"/> is true. Override to
    /// scope a per-route or per-tenant sidebar so multiple sidebars on the same origin
    /// don't clobber each other's state.
    /// </summary>
    [Parameter] public string PersistenceKey { get; set; } = "lumeo.sidebar.collapsed";

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Transient hover/focus-driven expansion for the MiniRail variant. Lives on the
    // provider (not SidebarComponent) so descendants — most importantly
    // SidebarMenuButton — can react via the cascaded SidebarState and reveal their
    // LabelContent during hover-expansion, not just on pinned expand.
    private bool _hoverExpanded;
    private IAsyncDisposable? _shortcutHandle;
    private string? _registeredShortcut;
    private bool _viewportSubscribed;

    // True when the sidebar should render + behave as collapsed for descendants. For
    // MiniRail this is IsCollapsed unless the user is hovering / keyboard-focused on
    // the rail. Other variants ignore the hover state.
    private bool EffectiveCollapsed
        => IsCollapsed && !(Variant == SidebarVariant.MiniRail && _hoverExpanded);

    // Off-canvas sheet behaviour only kicks in on mobile, and only when opted in.
    private bool IsMobileSheet => MobileSheet && Responsive.IsMobile;

    private string CssClass
    {
        get
        {
            // The mobile sheet (or the Overlay variant) needs a positioning
            // context for its absolutely-positioned panel + scrim.
            var positioned = (Variant == SidebarVariant.Overlay || IsMobileSheet) ? "relative overflow-hidden" : "";
            return Cx.Merge("flex h-full w-full", positioned, Class);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // React to viewport changes so the mobile-sheet treatment flips on the
        // md boundary without a manual refresh.
        if (firstRender && MobileSheet && !_viewportSubscribed)
        {
            _viewportSubscribed = true;
            Responsive.ViewportChanged += OnViewportChanged;
            try { await Responsive.EnsureInitialisedAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            StateHasChanged();
        }

        // Run every render (not just firstRender) so a changed ToggleShortcut
        // parameter re-registers; SyncShortcutAsync is a no-op when unchanged.
        await SyncShortcutAsync();

        if (firstRender && PersistCollapsed)
        {
            try
            {
                var stored = await Interop.LoadFromLocalStorage(PersistenceKey);
                // Only restore if storage actually held a value AND it differs from the
                // current parameter — avoids a redundant cascade refresh on every mount.
                if (stored is "true" or "false")
                {
                    var restored = stored == "true";
                    if (restored != IsCollapsed)
                    {
                        IsCollapsed = restored;
                        await IsCollapsedChanged.InvokeAsync(IsCollapsed);
                        StateHasChanged();
                    }
                }
            }
            catch (Microsoft.JSInterop.JSDisconnectedException)
            {
                // Circuit dropped between firstRender scheduling and the storage call.
                // Fall through silently — the cascade keeps the parameter default.
            }
        }
    }

    // (Re)registers the toggle shortcut when ToggleShortcut changes. Releases a
    // previous registration first so a changed combo doesn't leave a ghost.
    private async Task SyncShortcutAsync()
    {
        if (_registeredShortcut == ToggleShortcut) return;
        if (_shortcutHandle is not null)
        {
            try { await _shortcutHandle.DisposeAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _shortcutHandle = null;
        }
        _registeredShortcut = ToggleShortcut;
        if (string.IsNullOrWhiteSpace(ToggleShortcut)) return;
        try
        {
            _shortcutHandle = await Shortcuts.RegisterAsync(ToggleShortcut!, Toggle);
        }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        catch (InvalidOperationException) { } // JS unavailable during prerender
    }

    private void OnViewportChanged(Lumeo.Services.ViewportInfo _)
    {
        // A breakpoint crossing may flip IsMobileSheet — re-render the cascade.
        InvokeAsync(StateHasChanged);
    }

    private async Task Toggle()
    {
        IsCollapsed = !IsCollapsed;
        await IsCollapsedChanged.InvokeAsync(IsCollapsed);
        await InvokeAsync(StateHasChanged);
        if (PersistCollapsed)
        {
            try { await Interop.SaveToLocalStorage(PersistenceKey, IsCollapsed ? "true" : "false"); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    // Called by SidebarComponent's @onmouseenter / @onmouseleave / focus handlers.
    // Only meaningful for MiniRail — other variants set this but their CSS / button
    // logic ignores it via the EffectiveCollapsed predicate.
    private void SetHoverExpanded(bool value)
    {
        if (_hoverExpanded == value) return;
        _hoverExpanded = value;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_viewportSubscribed)
            Responsive.ViewportChanged -= OnViewportChanged;
        if (_shortcutHandle is not null)
        {
            try { await _shortcutHandle.DisposeAsync(); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    // Kept as a 3-positional record so the v3.10.0 generated constructor + Deconstruct
    // signature still compiles for external callers (this record is meant for our own
    // cascade but is technically public). The new fields land as init-only props
    // with defaults — fully additive.
    public record SidebarState(
        bool IsCollapsed,
        EventCallback Toggle,
        SidebarVariant Variant)
    {
        /// <summary>True when descendants should render in their collapsed appearance.
        /// For MiniRail this is <see cref="IsCollapsed"/> unless the user is hovering
        /// the rail; other variants always match <see cref="IsCollapsed"/>.</summary>
        public bool EffectiveCollapsed { get; init; } = IsCollapsed;

        /// <summary>Called by <c>SidebarComponent</c> on hover / focus to flip the
        /// MiniRail hover-expansion. No-op for other variants.</summary>
        public EventCallback<bool> SetHoverExpanded { get; init; }

        /// <summary>True when the sidebar should render as a mobile off-canvas
        /// sheet (opted into via <c>MobileSheet</c> and currently on a mobile
        /// viewport). <c>SidebarComponent</c> swaps to the slide-in + scrim
        /// treatment when set.</summary>
        public bool IsMobileSheet { get; init; }
    }

    /// <summary>
    /// Layout strategy for the sidebar.
    /// <list type="bullet">
    /// <item><c>Push</c> — collapses to zero width, pushing main content to the edge.</item>
    /// <item><c>Overlay</c> — floats above content with a dismissible scrim.</item>
    /// <item><c>Icon</c> — collapses to a narrow icon rail that stays put until toggled back.</item>
    /// <item><c>MiniRail</c> — same icon-rail width when collapsed, but expands to full
    /// width on hover or keyboard focus and collapses again on leave. Material’s standard
    /// collapsed-sidebar pattern; uses <c>Toggle()</c> to pin open.</item>
    /// </list>
    /// </summary>
    public enum SidebarVariant { Push, Overlay, Icon, MiniRail }
}

@namespace Lumeo

<div class="@CssClass" role="none" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("mx-3 my-2 h-px bg-border", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<Tooltip>
    <TooltipTrigger AsChild>
        <ChildContentSlot Context="slot">
            <button type="button" class="@CssClass" @onclick="State.Toggle" aria-label="@L["Sidebar.Toggle"]" aria-expanded="@((State?.IsCollapsed != true).ToString().ToLowerInvariant())" @attributes="MergeAttrs(slot.Attributes)">
                @if (State?.IsCollapsed == true)
                {
                    <Blazicon Svg="Lucide.PanelLeftOpen" class="h-4 w-4" />
                }
                else
                {
                    <Blazicon Svg="Lucide.PanelLeftClose" class="h-4 w-4" />
                }
            </button>
        </ChildContentSlot>
    </TooltipTrigger>
    <TooltipContent>@L["Sidebar.Toggle"]</TooltipContent>
</Tooltip>

@code {
    [CascadingParameter] public SidebarProvider.SidebarState State { get; set; } = default!;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Merge consumer AdditionalAttributes with the Tooltip AsChild slot attributes
    // (aria-describedby while open) onto the single button.
    private Dictionary<string, object> MergeAttrs(IReadOnlyDictionary<string, object> slotAttrs)
    {
        var d = new Dictionary<string, object>();
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value;
        foreach (var kv in slotAttrs) d[kv.Key] = kv.Value;
        return d;
    }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 h-9 w-9", Class);
}
